def generate_lock_file(packages, output_path):
    """
    Generate a Poetry lock file from the given packages.

    Args:
        packages (list): List of package specifications.
        output_path (str): Path to write the lock file.

    Returns:
        str: Path to the generated lock file.
    """

    # Create a temporary directory for the build process
    temp_dir = EnvManager.get_temp_directory()
    ensure_dir_exists(temp_dir)

    # Initialize Poetry with the given packages
    poetry = EnvManager.create_poetry(
        root=temp_dir,
        source_requirement=Source.from_pypi("poetry")
    )
    poetry.add_dependencies(packages)

    # Build and lock the dependencies
    poetry.build()
    poetry.lock()

    # Get the path to the generated lock file
    lock_file_path = os.path.join(temp_dir, "poetry.lock")

    # Copy the lock file to the specified output path
    with open(lock_file_path, "rb") as f_in:
        with open(output_path, "wb") as f_out:
            f_out.write(f_in.read())

    return lock_file_path

def update_lock_file(requirements_txt_path, output_path):
    """
    Update a Poetry lock file from the given requirements.txt.

    Args:
        requirements_txt_path (str): Path to the requirements.txt file.
        output_path (str): Path to write the updated lock file.

    Returns:
        str: Path to the generated lock file.
    """

    # Read the contents of the requirements.txt file
    with open(requirements_txt_path, "r") as f_in:
        lines = [line.strip() for line in f_in.readlines()]

    # Parse the package specifications from the requirements.txt file
    packages = []
